// Time:  O(n)
// Space: O(1)

class Solution {
public:
    bool makeEqual(vector<string>& words) {
        vector<int> cnt(26);
        for (const auto& w : words) {
            for (const auto& c : w) {
                ++cnt[c - 'a'];
            }
        }
        return all_of(cbegin(cnt), cend(cnt),
                      [&words](int c) {
                          return c % size(words) == 0;
                      });
    }
};

# Time:  O(n)
# Space: O(1)

import collections


class Solution(object):
    def makeEqual(self, words):
        """
        :type words: List[str]
        :rtype: bool
        """
        cnt = collections.defaultdict(int)
        for w in words:
            for c in w:
                cnt[c] += 1
        return all(v%len(words) == 0 for v in cnt.itervalues())
